import { api } from '@semparar/mf-app-user';
import type { AxiosResponse } from 'axios';

export interface OrderDetailItemDto {
  id: string;
  unitaryValue: number;
  quantity: number;
  description: string;
}

export interface OrderDetailBenefitDto {
  id: string;
  type: string;
  value: number;
  description: string;
}

export interface MarketplaceItemDto {
  name: string;
  quantity: number;
  valuePoints: number;
  imageUrl?: string;
}

export interface MarketplaceOrderDto {
  vendor?: string;
  items?: MarketplaceItemDto[];
}

export interface MarketplacePaymentDto {
  paymentType: string;
}

export interface MarketplaceDto {
  orders?: MarketplaceOrderDto[];
  payments?: MarketplacePaymentDto[];
  shippingValuePoints?: number;
  valuePoints?: number;
}

export interface OrderDetailDataDto {
